   # Mo Spiegel, Period 3B
   def getSeverityIndex(self):
       for i in self.symptoms:
           # Assigns each symptom of the disease a severity index based on its tier
           # The sum of each symptoms' severity index is the disease severity
           if i == "上火(Shànghuǒ)":
               self.severities.append(random.randint(7, 15))
               self.sevIndex = self.sevIndex + self.severities[len(self.severities) - 1]

           elif i == "气虚(Qì Xū)":
               self.severities.append(random.randint(7, 15))
               self.sevIndex = self.sevIndex + self.severities[len(self.severities) - 1]

           elif i == "肝气郁结(Gān Qì Yù Jié)":
               self.severities.append(random.randint(7, 15))
               self.sevIndex = self.sevIndex + self.severities[len(self.severities) - 1]

           elif i == "风寒(Fēng Hán)":
               self.severities.append(random.randint(7, 15))
               self.sevIndex = self.sevIndex + self.severities[len(self.severities) - 1]

           elif i == "痰湿(Tán Shī)":
               self.severities.append(random.randint(5, 8))
               self.sevIndex = self.sevIndex + self.severities[len(self.severities) - 1]

           elif i == "湿热(Shī Rè)":
               self.severities.append(random.randint(5, 8))
               self.sevIndex = self.sevIndex + self.severities[len(self.severities) - 1]

           elif i == "风热(Fēng Rè)":
               self.severities.append(random.randint(5, 8))
               self.sevIndex = self.sevIndex + self.severities[len(self.severities) - 1]

           elif i == "阳虚(Yáng Xū)":
               self.severities.append(random.randint(5, 11))
               self.sevIndex = self.sevIndex + self.severities[len(self.severities) - 1]

           elif i == "阴虚(Yīn Xū)":
               self.severities.append(random.randint(5, 11))
               self.sevIndex = self.sevIndex + self.severities[len(self.severities) - 1]

           elif i == "血瘀(Xuè Yū)":
               self.severities.append(random.randint(5, 11))
               self.sevIndex = self.sevIndex + self.severities[len(self.severities) - 1]




